import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { adminService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/admin/admin-auditlog.css';
import '../../styles/admin-layout.css';
import { pushToast } from '../../utils/toastBridge'

const ACTION_MAP = {
  CREATE: { vi: 'Táº¡o má»›i', color: '#0ea5e9' },
  UPDATE: { vi: 'Cáº­p nháº­t', color: '#2563eb' },
  DELETE: { vi: 'XÃ³a', color: '#ef4444' },
  LOGIN: { vi: 'ÄÄƒng nháº­p', color: '#22c55e' },
  LOGIN_FAILED: { vi: 'ÄÄƒng nháº­p tháº¥t báº¡i', color: '#dc2626' },
  LOCK: { vi: 'KhÃ³a tÃ i khoáº£n', color: '#f97316' },
  UNLOCK: { vi: 'Má»Ÿ khÃ³a tÃ i khoáº£n', color: '#14b8a6' },
};

const ROLE_MAP = {
  ADMIN: 'Quáº£n trá»‹ viÃªn',
  MANAGER: 'Quáº£n lÃ½',
  TECHNICIAN: 'Ká»¹ thuáº­t viÃªn',
  WORKER: 'CÃ´ng nhÃ¢n',
  ACCOUNTANT: 'Káº¿ toÃ¡n',
  STOREKEEPER: 'Quáº£n lÃ½ kho',
  OWNER: 'Chá»§ tráº¡i',
};

const MODULE_MAP = {
  USER: 'NgÆ°á»i dÃ¹ng',
  USERS: 'NgÆ°á»i dÃ¹ng',
  USER_ROLE: 'Vai trÃ²',
  POND: 'Ao',
  PONDS: 'Ao',
  SEASON: 'MÃ¹a vá»¥',
  SEASONS: 'MÃ¹a vá»¥',
  PRODUCT: 'Sáº£n pháº©m',
  PRODUCTS: 'Sáº£n pháº©m',
  DISEASE: 'Bá»‡nh tÃ´m',
  DISEASES: 'Bá»‡nh tÃ´m',
  SENSOR: 'Cáº£m biáº¿n',
  SENSORS: 'Cáº£m biáº¿n',
  TASK: 'CÃ´ng viá»‡c',
  TASKS: 'CÃ´ng viá»‡c',
  ENVIRONMENT_LOG: 'Nháº­t kÃ½ mÃ´i trÆ°á»ng',
  FEED_LOG: 'Nháº­t kÃ½ cho Äƒn',
  CULTIVATION_LOG: 'Nháº­t kÃ½ canh tÃ¡c',
  NOTIFICATION: 'ThÃ´ng bÃ¡o',
  AUTH: 'XÃ¡c thá»±c',
};

const DAYS_OPTIONS = [
  { value: 1, label: '24 giá» qua' },
  { value: 7, label: '7 ngÃ y gáº§n nháº¥t' },
  { value: 30, label: '30 ngÃ y gáº§n nháº¥t' },
  { value: 90, label: '90 ngÃ y gáº§n nháº¥t' },
];

const MODULE_OPTIONS = [
  { value: '', label: 'Táº¥t cáº£ module' },
  { value: 'USER', label: 'NgÆ°á»i dÃ¹ng' },
  { value: 'USER_ROLE', label: 'Vai trÃ²' },
  { value: 'POND', label: 'Ao nuÃ´i' },
  { value: 'SEASON', label: 'MÃ¹a vá»¥' },
  { value: 'TASK', label: 'CÃ´ng viá»‡c' },
  { value: 'DISEASE', label: 'Bá»‡nh tÃ´m' },
  { value: 'SENSOR', label: 'Cáº£m biáº¿n' },
  { value: 'ENVIRONMENT_LOG', label: 'MÃ´i trÆ°á»ng' },
  { value: 'FEED_LOG', label: 'Cho Äƒn' },
  { value: 'NOTIFICATION', label: 'ThÃ´ng bÃ¡o' },
];

const SEVERITY_OPTIONS = [
  { value: '', label: 'Táº¥t cáº£ má»©c Ä‘á»™' },
  { value: 'LOW', label: 'Tháº¥p' },
  { value: 'MEDIUM', label: 'Trung bÃ¬nh' },
  { value: 'HIGH', label: 'Cao' },
];

const ACTION_OPTIONS = [
  { value: '', label: 'Táº¥t cáº£ hÃ nh Ä‘á»™ng' },
  { value: 'CREATE', label: 'Táº¡o má»›i' },
  { value: 'UPDATE', label: 'Cáº­p nháº­t' },
  { value: 'DELETE', label: 'XÃ³a' },
  { value: 'LOGIN', label: 'ÄÄƒng nháº­p' },
  { value: 'LOGIN_FAILED', label: 'ÄÄƒng nháº­p tháº¥t báº¡i' },
  { value: 'LOCK', label: 'KhÃ³a tÃ i khoáº£n' },
  { value: 'UNLOCK', label: 'Má»Ÿ khÃ³a tÃ i khoáº£n' },
];

function normalizeEntityType(entityType) {
  if (!entityType) return '';
  return String(entityType)
    .trim()
    .replace(/[-\s]+/g, '_')
    .replace(/__+/g, '_')
    .toUpperCase();
}

function getSeverityVi(severity) {
  const key = String(severity || 'LOW').toUpperCase();
  if (key === 'HIGH') return 'Cao';
  if (key === 'MEDIUM') return 'Trung bÃ¬nh';
  return 'Tháº¥p';
}

function safeJsonParse(value) {
  if (!value) return null;
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(value);
  } catch (error) {
    return null;
  }
}

export const AdminAuditLog = () => {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const error = null;
  const [searchQuery, setSearchQuery] = useState('');
  const [pageSize, setPageSize] = useState(10);
  const [currentPage, setCurrentPage] = useState(1);
  const [uiFilters, setUiFilters] = useState({
    days: 7,
    module: '',
    severity: '',
    action: '',
  });
